.flow {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 14px;
  align-items: stretch;
  margin-top: 8px;
}
.flow-step {
  background: #fffdf7;
  border: 1.5px solid var(--rule);
  border-radius: 12px;
  padding: 10px 12px;
  text-align: center;
  font-size: 16px;
  position: relative;
  box-shadow: 2px 3px 0 rgba(0,0,0,0.04);
}
.flow-step .num {
  display: inline-block;
  background: var(--ink);
  color: var(--paper);
  border-radius: 999px;
  width: 22px;
  height: 22px;
  line-height: 22px;
  font-size: 14px;
  margin-bottom: 4px;
}
.flow-step.off-gross { background: #fdecec; }
.flow-step.inside    { background: #fff4d6; }
.flow-step.outside   { background: #e3d4f0; }
.flow-step.split     { background: #d4e8d4; }
.flow-step.post      { background: #d4e2f0; }
.flow-arrow {
  text-align: center;
  font-size: 22px;
  align-self: center;
}

