  padding: 8px 10px;
  border: 1px solid #d0c8b0;
  text-align: center;
  font-family: "Caveat", cursive;
  font-size: 17px;
}
.matrix th {
  background: #f0ead8;
  font-weight: 400;
}
.matrix td.deal { text-align: left; font-weight: 600; }
.matrix .yes { background: var(--good); }
.matrix .no  { background: var(--bad);  }
.matrix .partial { background: var(--warn); }

.legend {
  display: flex;
  gap: 16px;
  justify-content: center;
  margin-top: 10px;
  font-size: 16px;
}
.legend .swatch {
  display: inline-block;
  width: 16px;
  height: 16px;
  border-radius: 3px;
  margin-right: 5px;
  vertical-align: middle;
  border: 1px solid rgba(0,0,0,0.1);
}

.callout {
  border-left: 4px solid var(--rule);
  padding: 8px 14px;
  margin: 8px 0;
  background: #fffdf7;
  font-size: 17px;
}
.callout.bad { border-left-color: #c25a5a; background: var(--bad); }
.callout.good { border-left-color: #4f8a4f; background: var(--good); }

.small { font-size: 15px; color: var(--muted); }

